SELECT 
FROM bs_unit
WHERE deleted = 0

    AND enterprise_id = #{enterpriseId}


    AND name LIKE CONCAT('%', #{name}, '%')


    AND unit_type = #{unitType}


    AND sub_category = #{subCategory}

ORDER BY unit_type, id

mapper.update:
UPDATE bs_unit
SET deleted = 1, update_by = #{updateBy}, update_time = NOW()
WHERE id = #{id}
